arguments.command:
cat > /tmp/test_stackalloc_nint.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> a = stackalloc nint[4];
        a[0] = 10;
        a[1] = 20;
        a[2] = 30;
        a[3] = 40;

        Console.WriteLine($"Span<nint> length: {a.Length}");
        for (int i = 0; i < a.Length; i++)
            Console.WriteLine($"  a[{i}] = {a[i]}");

        Span<nuint> b = stackalloc nuint[3];
        b[0] = 100;
        b[1] = 200;
        b[2] = 300;

        Console.WriteLine($"Span<nuint> length: {b.Length}");
        for (int i = 0; i < b.Length; i++)
            Console.WriteLine($"  b[{i}] = {b[i]}");

        Console.WriteLine($"nint size: {sizeof(nint)} bytes");
    }
}
EOF
cd /tmp && dotnet-script test_stackalloc_nint.cs 2>/dev/null || dotnet run --project . 2>/dev/null || (dotnet new console -o stackalloc_test --force -n StackallocTest && cp test_stackalloc_nint.cs stackalloc_test/Program.cs && cd stackalloc_test && dotnet run)

